daimo:inputSchema.jsonSchema:
{
  "type": "object",
  "properties": {
    "trip_id": {
      "type": "string",
      "description": "GTFS trip identifier"
    },
    "from_stop_id": {
      "type": "string",
      "description": "Origin stop identifier"
    },
    "to_stop_id": {
      "type": "string",
      "description": "Destination stop identifier"
    },
    "route_id": {
      "type": "string",
      "description": "GTFS route identifier"
    },
    "scheduled_travel_time": {
      "type": "number",
      "description": "Scheduled segment travel time in seconds"
    },
    "shape_distance": {
      "type": "number",
      "description": "Segment distance in meters"
    },
    "is_peak": {
      "type": "integer",
      "description": "Peak-hour indicator",
      "minimum": 0,
      "maximum": 1
    },
    "hour_sin": {
      "type": "number",
      "description": "Cyclic hour sine encoding"
    },
    "hour_cos": {
      "type": "number",
      "description": "Cyclic hour cosine encoding"
    },
    "weekday_sin": {
      "type": "number",
      "description": "Cyclic weekday sine encoding"
    },
    "weekday_cos": {
      "type": "number",
      "description": "Cyclic weekday cosine encoding"
    },
    "previous_delay_ratio": {
      "type": "number",
      "description": "Previous delay divided by scheduled travel time"
    },
    "previous_delay_delta": {
      "type": "number",
      "description": "Previous delay delta in seconds"
    }
  },
  "required": [
    "trip_id",
    "from_stop_id",
    "to_stop_id",
    "route_id",
    "scheduled_travel_time",
    "shape_distance",
    "is_peak",
    "hour_sin",
    "hour_cos",
    "weekday_sin",
    "weekday_cos",
    "previous_delay_ratio",
    "previous_delay_delta"
  ]
}
